// One item per discovered business that has a website. No website = no way to find a
// conspicuously published address, so it is dropped (logged in notes, not queued).
const body = $input.first().json || {};
const places = Array.isArray(body.places) ? body.places : [];
const cfg = $('Cohort Config').first().json;
const out = [];
for (let i = 0; i < places.length; i++) {
  const p = places[i] || {};
  const website = String(p.websiteUri || '').trim();
  if (!website) continue; // cannot source a published address without a site
  if (String(p.businessStatus || '').toUpperCase() === 'CLOSED_PERMANENTLY') continue;
  out.push({ json: {
    place_id: p.id || '',
    business_name: (p.displayName && p.displayName.text) || '',
    website: website,
    phone: p.nationalPhoneNumber || '',
    address: p.formattedAddress || '',
    rating: p.rating || '',
    review_count: p.userRatingCount || '',
    category: cfg.category || '',
    location: cfg.location || '',
    archetype: cfg.archetype || 'trades',
  } });
}
return out;

// Extract the published email from each business's own homepage, then apply the two
// non-negotiable gates: (1) never re-contact an address already in the sheet (any status),
// (2) never contact a suppressed / unsubscribed / bounced address. Build the enrichment
// request only for genuinely fresh, contactable prospects.

const places = $('Explode Places').all().map(function (i) { return i.json; });
const fetched = $('Fetch Website').all();

// --- Build the existing + suppression sets from the live sheet ---
const sheetRows = $('Read Prospects Sheet').all().map(function (i) { return i.json; });
// Safe-fail: if the suppression read is empty, abort rather than risk re-contacting an opt-out.
// (The live prospects sheet always has rows; 0 means the read did not run, e.g. a node-order issue.)
if (!sheetRows.length) throw new Error('Suppression read returned 0 rows; aborting so no opt-out can be re-contacted.');
const existingEmails = new Set();
const suppressedEmails = new Set();
const existingBusinesses = new Set();
const SUPPRESS = ['unsubscribed', 'suppressed', 'rejected', 'bounced'];
for (const r of sheetRows) {
  const em = String(r.email || '').trim().toLowerCase();
  const st = String(r.status || '').trim().toLowerCase();
  const bn = String(r.business_name || '').trim().toLowerCase();
  if (em) existingEmails.add(em);
  if (em && SUPPRESS.indexOf(st) !== -1) suppressedEmails.add(em);
  if (bn) existingBusinesses.add(bn);
}

// --- Fetch Layer 1 brain for the enrichment prompt (human-write, read at runtime) ---
const repo = 'https://raw.githubusercontent.com/isaiahwong-bit/Digital-Artifacts';
const refs = ['main', 'feat/automation-journey-live', 'feat/sales-ops-automation'];
const files = ['outbound-icp', 'field-service', 'company-brief'];
const brain = {};
for (const f of files) {
  let got = null;
  for (const ref of refs) {
    try { got = await this.helpers.httpRequest({ method: 'GET', url: repo + '/' + ref + '/brain/' + f + '.md', encoding: 'text', json: false }); break; } catch (e) { got = null; }
  }
  if (got === null) throw new Error('Brain file unreachable on any branch: ' + f);
  brain[f] = got;
}

// --- Email extraction helpers ---
const JUNK = /(\.png|\.jpg|\.jpeg|\.gif|\.webp|\.svg|sentry\.|wixpress|example\.|yourdomain|your-email|email@|@2x|@sentry|godaddy|squarespace|cloudflare|\.wix|domain\.com)/i;
function extractEmails(html, siteUrl) {
  if (!html || typeof html !== 'string') return [];
  const found = new Set();
  const mailtoRe = /mailto:([^"'?>\s]+@[^"'?>\s]+)/gi;
  const plainRe = /[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/g;
  let m;
  while ((m = mailtoRe.exec(html)) !== null) found.add(m[1].toLowerCase());
  const plain = html.match(plainRe) || [];
  for (const e of plain) found.add(e.toLowerCase());
  let list = Array.from(found).filter(function (e) { return !JUNK.test(e) && e.length < 80; });
  // Prefer an address on the same domain as the website.
  let host = '';
  try { host = new URL(siteUrl).hostname.replace(/^www\./, ''); } catch (e) { host = ''; }
  if (host) {
    const sameDomain = list.filter(function (e) { return e.split('@')[1] && e.split('@')[1].indexOf(host) !== -1; });
    if (sameDomain.length) list = sameDomain;
  }
  // Prefer role / catch-all addresses over personal noise.
  const ROLE = /^(info|hello|admin|office|accounts|enquiries|enquiry|contact|sales|bookings|service)@/i;
  list.sort(function (a, b) { return (ROLE.test(b) ? 1 : 0) - (ROLE.test(a) ? 1 : 0); });
  return list;
}

const now = new Date();
const stamp = now.getTime().toString(36);
const seenThisRun = new Set();
const fresh = [];

for (let i = 0; i < places.length; i++) {
  const p = places[i];
  const fItem = fetched[i] ? fetched[i].json : {};
  const html = (fItem && (fItem.data || fItem.body || '')) || '';
  const emails = extractEmails(html, p.website);
  const email = emails.length ? emails[0] : '';
  const bn = String(p.business_name || '').trim().toLowerCase();

  // GATE 1: no published address found -> not a defensible send. Drop (do not queue).
  if (!email) continue;
  // GATE 2: hard suppression. Never re-contact an opt-out / bounce.
  if (suppressedEmails.has(email)) continue;
  // GATE 3: never double-touch an address already in the sheet (any status).
  if (existingEmails.has(email)) continue;
  // GATE 4: skip a business already in the sheet under a different address.
  if (existingBusinesses.has(bn)) continue;
  // GATE 5: de-dupe within this run.
  if (seenThisRun.has(email)) continue;
  seenThisRun.add(email);

  const websiteText = String(html).replace(/<script[\s\S]*?<\/script>/gi, ' ').replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 4000);

  const enrichSystem = 'You are the Digital Artifacts prospect-enrichment step (a Layer 2 skill). You read a small Australian business public footprint and return a tight, honest enrichment record. You NEVER invent a pain. If the footprint does not evidence a specific repetitive-ops pain, set pain_evidenced false and leave likely_pain empty. HARD RULES: no em dashes ever, Australian businesses and the three ICP archetypes only, fit_hint is advisory only. Return JSON only, no prose, no markdown fences.';
  const enrichSchema = '{"archetype":"trades|services|sales|other","size_estimate":"micro (1-3)|small (4-20)|mid (21-50)|larger (50+)|unknown","contact_role_guess":"owner|office manager|operations|unknown","likely_pain":"one specific weekly repetitive task drawn from the footprint, or empty","pain_evidenced":true,"evidence":"the specific footprint detail supporting the pain, or empty","fit_hint":"strong|plausible|weak|not_fit","notes":"one sentence for Isaiah"}';
  const content = '<icp>\n' + brain['outbound-icp'] + '\n</icp>\n\n'
    + '<field_service>\n' + brain['field-service'] + '\n</field_service>\n\n'
    + '<company>\n' + brain['company-brief'] + '\n</company>\n\n'
    + '<business>\nName: ' + (p.business_name || '') + '\nCategory searched: ' + (p.category || '') + '\nLocation: ' + (p.location || '') + '\nGoogle rating: ' + (p.rating || '') + ' from ' + (p.review_count || '') + ' reviews\nWebsite: ' + (p.website || '') + '\nWebsite text (extract):\n' + websiteText + '\n</business>\n\n'
    + 'Return strictly this JSON, nothing else:\n' + enrichSchema;
  const enrich_request = { model: 'claude-sonnet-4-6', max_tokens: 600, system: enrichSystem, messages: [{ role: 'user', content: content }] };

  fresh.push({ json: {
    prospect_id: 'P' + stamp + '-' + i,
    business_name: p.business_name || '',
    email: email,
    email_source: p.website || '',
    contact_name: '',
    contact_role: '',
    industry: p.category || '',
    location: p.location || '',
    size: '',
    notes: 'Google ' + (p.rating || '?') + ' from ' + (p.review_count || '0') + ' reviews. Phone ' + (p.phone || 'n/a') + '. Sourced via Places search: "' + (p.category || '') + ' ' + (p.location || '') + '".',
    sourced_at: now.toISOString(),
    enrich_request: enrich_request,
  } });
}

if (fresh.length === 0) {
  // Nothing fresh and contactable this run. Emit a single no-op marker so the run ends cleanly.
  return [{ json: { _no_fresh_prospects: true, scanned: places.length } }];
}
return fresh;

// Parse the enrichment, merge it onto the prospect row, queue it for workflow-f.
const prev = $('Extract Email + Suppress + Dedupe').all();
// Map enrichment responses back to their prospect by index (HTTP preserves order).
const me = $input.all();
const out = [];
for (let i = 0; i < me.length; i++) {
  const row = (prev[i] && prev[i].json) || {};
  const raw = (me[i] && me[i].json && me[i].json.content && me[i].json.content[0] && me[i].json.content[0].text) || '';
  let e;
  try { const s = raw.indexOf('{'); const x = raw.lastIndexOf('}'); e = JSON.parse(raw.slice(s, x + 1)); }
  catch (err) { e = { archetype: row.industry || 'trades', size_estimate: 'unknown', contact_role_guess: 'unknown', likely_pain: '', pain_evidenced: false, evidence: '', fit_hint: 'plausible', notes: 'Enrichment parse failed, queued as plausible for the qualifier to grade.' }; }
  out.push({ json: {
    prospect_id: row.prospect_id || '',
    business_name: row.business_name || '',
    contact_name: row.contact_name || '',
    contact_role: e.contact_role_guess && e.contact_role_guess !== 'unknown' ? e.contact_role_guess : '',
    email: row.email || '',
    email_source: row.email_source || '',
    industry: row.industry || '',
    location: row.location || '',
    size: e.size_estimate || '',
    likely_pain: e.likely_pain || '',
    fit_hint: e.fit_hint || '',
    notes: (row.notes || '') + (e.evidence ? ' Pain evidence: ' + e.evidence : '') + (e.notes ? ' | ' + e.notes : ''),
    status: 'queued',
    next_action: '',
    sourced_at: row.sourced_at || new Date().toISOString(),
  } });
}
return out;
